package com.raonmate.backend.budget.api; import com.raonmate.backend.budget.application.BudgetService; import jakarta.validation.Valid; import java.util.UUID; import lombok.RequiredArgsConstructor; import org.springframework.web.bind.annotation.*; @RestController @RequestMapping("/api/workshops/{workshopId}/budget") @RequiredArgsConstructor public class BudgetController{private final BudgetService service;@GetMapping public BudgetResponse get(@PathVariable UUID workshopId){return service.get(workshopId);}@PostMapping("/initialize") public BudgetResponse initialize(@PathVariable UUID workshopId){return service.initialize(workshopId);}@PutMapping public BudgetResponse update(@PathVariable UUID workshopId,@Valid @RequestBody BudgetRequest request){return service.update(workshopId,request);}}
